import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    useEffect(() => {
        axios.get('http://localhost:5000/api/songs').then(res => setSongs(res.data));
    }, []);

    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    const currentSong = songs[currentIndex];

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '150px' }}>
            <h2 style={{ marginBottom: '30px', fontWeight: 'bold' }}>KHÁM PHÁ ÂM NHẠC</h2>
            
            {/* GRID LAYOUT */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '25px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={cardStyle}>
                        <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '12px' }}>
                            <img src={`http://localhost:5000${song.imageUrl}`} style={imgStyle} alt="" />
                            <button onClick={() => playSong(index)} style={playOverlayBtn}>▶</button>
                        </div>
                        <h4 style={{ margin: '12px 0 5px 0' }}>{song.title}</h4>
                        <p style={{ color: '#666', fontSize: '14px', margin: 0 }}>{song.artist}</p>
                        
                        <div style={{ marginTop: '10px', paddingTop: '10px', borderTop: '1px solid #eee', fontSize: '12px' }}>
                            Đăng bởi: 
                            <Link to={`/profile/${song.userId}`} style={{ color: '#1db954', textDecoration: 'none', fontWeight: 'bold', marginLeft: '5px' }}>
                                {song.uploaderName}
                            </Link>
                        </div>
                    </div>
                ))}
            </div>

            {/* MINI PLAYER BAR */}
            {currentSong && (
                <div style={playerBar}>
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} alt="" />
                        <div>
                            <div style={{ fontWeight: 'bold' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>
                    <div style={{ width: '40%', textAlign: 'center' }}>
                        <button onClick={() => isPlaying ? audioRef.current.pause() : audioRef.current.play()} style={mainPlayBtn}>
                            {isPlaying ? '⏸' : '▶'}
                        </button>
                        <audio ref={audioRef} src={`http://localhost:5000${currentSong.songUrl}`} autoPlay onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)} />
                    </div>
                    <div style={{ width: '30%' }}></div>
                </div>
            )}
        </div>
    );
};

const cardStyle = { background: '#fff', padding: '15px', borderRadius: '15px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' };
const imgStyle = { width: '100%', height: '200px', objectFit: 'cover' };
const playOverlayBtn = { position: 'absolute', bottom: '10px', right: '10px', background: '#1db954', color: 'white', border: 'none', width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', fontSize: '18px' };
const playerBar = { position: 'fixed', bottom: 0, left: 0, right: 0, background: '#181818', color: 'white', padding: '15px 40px', display: 'flex', alignItems: 'center', zIndex: 1000 };
const mainPlayBtn = { background: 'white', border: 'none', width: '45px', height: '45px', borderRadius: '50%', cursor: 'pointer', fontSize: '20px' };

export default Home;
